var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"행복에는 정해진 양이 있어요.","JPN":"幸せには決められた量があります。","ENG":"There is a finite amount to happiness.","TWN":"幸福是有限的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"모두가 행복한 세상은 꿈 같은 소리죠.","JPN":"みんなが幸せな世の中なんて、夢のような話です。","ENG":"A world where everyone can be happy is the stuff of fairy tales.","TWN":"所有人都很幸福的理想世界，只存在於夢裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"배부른 사람이 있으면 배고픈 사람이 있고, 오래 사는 사람이 있으면 태어나지도 못하고 죽는 사람이 있는 것처럼.","JPN":"満腹の人がいれば空腹の人がいて、長生きする人がいれば生まれることもできずに死ぬ人がいるように。","ENG":"While some go well-fed, there are those who go hungry. Some live long, fulfilling lives, while others perish before they draw their first breath.","TWN":"就好像有不愁吃喝的也有挨餓受凍的，有活得久的也有還沒出生就已經死去的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 자기가 행복하다는 사실을 알려면 어떻게 해야 될까요?","JPN":"それでは、自分が幸せだという事実を知るにはどうすれば良いのでしょうか？","ENG":"Then how can you tell if you're happy?","TWN":"那怎麼才能知道自己是幸福的呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"간단해요. 다른 사람이 고통 속에서 몸부림치는 모습을 보면 되죠.","JPN":"簡単です。他の人が苦しみ悶える姿を見ればいいのです。","ENG":"It's simple. All you need to do is see someone else writhing in agony.","TWN":"很簡單，當看到別人深陷於痛苦之中，你就懂了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"굶주림에, 질병에, 혹은 아픔에 못 이겨 울부짖는 모습을 감상하고 있노라면......","JPN":"飢えや病気、あるいは痛みに耐え切れず泣き叫ぶ姿を見ていると……","ENG":"As you gaze upon those who scream from hunger, disease, or pain...","TWN":"欣賞著人們因饑餓、疾病，或者因痛苦而哀嚎……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"자기가 얼마나 행복에 겨운지, 얼마나 우월한 위치에 서 있는지 실감할 수 있거든요.","JPN":"自分がどれだけ幸せ者なのか、どれだけ優位な立場にいるのかを実感できるのです。","ENG":"You'll come to truly appreciate how happy you really are. How superior your life truly is.","TWN":"你就能知道自己有多幸福，處於多高的位置了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 사람들은 인형을 찾는 거예요.","JPN":"だから、人々は人形を求める。","ENG":"That is why people seek puppets.","TWN":"所以人們才要想找個木偶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"자기 발 밑에 무릎 꿇은 채로 괴로워하고, 비명을 질러 줄......","JPN":"自分の足元に跪き、苦しんで悲鳴を上げてくれる……","ENG":"Lovely puppets...","TWN":"那種臣服於自己的腳下，痛苦掙扎並哀嚎的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"......사랑스러운 인형을.","JPN":"……可愛らしい人形を。","ENG":"that would scream and kneel in agony at their feet.","TWN":"……可愛的傀儡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"그거 참...... 이해하기 어려운 이야기네요.","JPN":"それはちょっと……理解できない話ですね。","ENG":"Well... I must say that's a lot to take in.","TWN":"你的話……真是讓人難以理解。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"후훗. 괜찮아요. 제 얘기를 들으면 다들 당신처럼 반응하니까요.","JPN":"ふふっ、いいんです。\\n私の話を聞いた人はみんなあなたのような反応をしますから。","ENG":"Hah hah. That's alright. Everyone responds the same way.","TWN":"哈哈，沒關係，很多人聽到我的話都跟你一樣的反應。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"크흠, 흠. 물론 그렇겠죠.","JPN":"こほん、ふむ。誰だってそうでしょう。","ENG":"Kahem, hem. I suppose they would.","TWN":"咳咳，咳。我想也是。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"그러니 이제 그만 질문에 대답해 주시면 좋겠습니다. 하랍 크로넨워스 씨.","JPN":"では、そろそろ質問にお答えいただきたいのですが。ハーラヴ・クロネンワースさん。","ENG":"Well, then. Would you please answer my question now, Miss Harab Cronenworth?","TWN":"好了，現在請你回答我的問題。哈拉普·克羅尼溫斯。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"저희 도시를 방문하는 목적이 무엇입니까?","JPN":"この都市を訪問される目的は何ですか？","ENG":"What is the purpose of your visit to our city?","TWN":"你來我們城市的目的是什麼？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"할로윈 페스티벌에 초청 받았어요. 퍼레이드 공연팀을 데리고 왔거든요.","JPN":"ハロウィンフェスティバルに招待されました。パレード公演チームを連れてきているんです。","ENG":"I've been invited to the Halloween festival. I brought a team to perform at the parade.","TWN":"我受邀參加萬聖節慶典，我還帶來了遊行表演團隊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"퍼레이드요?","JPN":"パレードですか？","ENG":"The parade?","TWN":"遊行表演？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"아......! 혹시 크로넨워스 인형극단의......?","JPN":"ああ……！　ひょっとしてクロネンワース人形劇団の……？","ENG":"Oh! You mean you're from the Cronenworth Puppet Troupe?","TWN":"啊……！你說的是克羅尼溫斯木偶劇團的……？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"네. 제가 단장을 맡고 있는 극단이에요.","JPN":"ええ。私が団長をしている劇団です。","ENG":"Yes. I'm the leader of that troupe.","TWN":"是的，我就是木偶劇團的團長。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"하하, 이거 실례했습니다! 제가 몰라 뵙고 그만!","JPN":"はは、これは失礼いたしました！　劇団の方だったとは！","ENG":"Oh, my! Please excuse me! I had no idea!","TWN":"哈哈，真是失禮了！請原諒我沒能認出你！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그래요? 저에 대해 알고 계시나요?","JPN":"あら、私のことをご存じなのですか？","ENG":"Oh, have you heard about me?","TWN":"噢？你認得我？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"그럼요. 저희 딸애가 아주 열렬한 팬이라서요.","JPN":"もちろんです。私の娘が熱烈なファンでしてね。","ENG":"Of course. My daughter is a big fan.","TWN":"當然，我的女兒可是你們劇團的忠實粉絲呢。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"딸애가 찍어 온 공연 영상을 본 적 있는데, 그런 굉장한 인형극은 난생 처음이었습니다!","JPN":"娘が撮ってきた公演の映像を見たことがあります。\\nあんなにすごい人形劇は生まれて初めてでした！","ENG":"I saw some of the videos of the performance she took, and I must say I've never seen anything so amazing!","TWN":"之前看過我女兒拍的影片，我生平第一次看到這麼大規模的木偶戲！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"인형들이 어찌나 실감나게 웃고 우는지 정말 사람 같더군요.","JPN":"人形たちがリアルに笑ったり泣いたりする様子は、まさに人間そのものでしたね。","ENG":"The way those puppets laughed and cried... It was as if they were real people.","TWN":"而那些木偶的表情個個都跟真人一樣。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"대체 어디서 그런 인형들을 만드셨습니까?","JPN":"あの人形はいったいどこで作っているんですか？","ENG":"How did you make puppets like that?","TWN":"那些木偶是怎麼做的？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 인형을 제작하는 방법은 비밀이에요.","JPN":"人形の製作方法は秘密なんです。","ENG":"Oh, I'm afraid that's a business secret.","TWN":"啊，木偶製作的辦法可是商業機密。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 인형들에게 재롱을 가르치는 법은 알려드릴 수 있답니다.","JPN":"ですが、人形たちにお遊戯を教える方法ならお教えできますよ。","ENG":"But I can show you how I get them to perform so well.","TWN":"不過，我可以告訴你怎麼操縱木偶。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그건 바로 이 채찍과 고통이죠.","JPN":"それは、鞭と苦痛です。","ENG":"I use this whip and pain.","TWN":"只要鞭打它們，讓它們痛苦就可以了"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아무리 형편없는 인형도 이 채찍만 있으면 멋진 재주를 부리게 만들 수 있거든요.","JPN":"どんなに出来損ないの人形でも、鞭さえあれば素晴らしい芸を仕込ませることができます。","ENG":"Even the most pathetic puppet can perform a neat trick as long as I've got this whip.","TWN":"即使再沒用的木偶，只要有這個鞭子，就可以讓它表演才藝。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"하하! 인형들을 가르치다니 재미있는 표현이로군요.","JPN":"はは！　人形に教えるなんて、面白い表現ですね。","ENG":"Hah hah, that's an interesting way to put it. Teaching your puppets, huh?","TWN":"哈哈！用鞭子？教育木偶？這個說法真有趣。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"과연 세계 최고의 인형술사는 인형들을 대하는 태도도 남다른 것 같습니다.","JPN":"世界最高の人形使いは、人形に対する態度も並外れているわけですね。","ENG":"I suppose as the world's best puppeteer, you have a unique approach to how you handle your puppets.","TWN":"世上首屈一指的木偶師對待木偶的方式真與眾不同啊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"이봐요! 언제까지 기다려야 됩니까?","JPN":"おい！　いつまで待たせる気かい？","ENG":"Hey! How much longer do we have to wait back here?","TWN":"喂！到底要等到什麼時候啊？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"이럴 거면 다른 창구도 열어야죠!","JPN":"長引くようなら他の窓口も開けてくれよ！","ENG":"Start another line if you're going to hold this one up for so long!","TWN":"你們這樣子早應該多開幾個售票口啊！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"아이고, 이거 제가 너무 오래 붙잡고 있었군요.","JPN":"おっと、長いこと引き留めてしまいましたね。","ENG":"Oops. Looks like I've been holding you up for too long.","TWN":"哎呀，是我耽誤您的時間了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L46_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"여기 신분증 받으시죠. 이제 통과하셔도 됩니다.","JPN":"身分証をどうぞ。もう通過して構いません。","ENG":"Here's your ID. You may go through now.","TWN":"請收好您的身份證，可以過去了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"아, 그렇지. 할로윈 코스튬 경연은 꼭 보세요. 저희 도시 명물이거든요.","JPN":"あ、そうだ。ハロウィンのコスチューム競演はぜひ見ていってください。\\n我が都市の名物なんです。","ENG":"Oh, that's right. Be sure to check out the Halloween costume performance. Our city is known for that.","TWN":"對了，一定要看萬聖節扮裝大賽，那可是我們城市的特色。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그렇군요. 좋은 정보 고마워요.","JPN":"そうですか。いい情報をありがとうございます。","ENG":"I see. Thank you for the information.","TWN":"好的，謝謝你。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"자, 다음 분! 다음 분 오세요!","JPN":"では、次の方！　次の方どうぞ！","ENG":"Alright, next!","TWN":"好，下一位！下一位可以過來了！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L2_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"......아차. 딸애 줄 사인 부탁 드린다는 걸 깜빡 했네.","JPN":"……しまった。娘に渡すサインをお願いするのをうっかり忘れてたな。","ENG":"Oh. I forgot to ask her for an autograph for my daughter.","TWN":"哎呀……忘了幫女兒要個簽名了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};